/* ===== ChangeFont Configuration =====
   Edit the variables below to customize.
   To use a Google Font, import it via the @import rule.
   ======================================= */

/* Uncomment and edit to import a Google Font: */
/* @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap'); */

:root {
  /* Font Family — change to any installed or imported font */
  --ba-font-family: "Inter", "Segoe UI", system-ui, -apple-system, sans-serif;

  /* Font Sizes per tag */
  --ba-font-size-body: 16px;
  --ba-font-size-h1: 2em;
  --ba-font-size-h2: 1.6em;
  --ba-font-size-h3: 1.3em;
  --ba-font-size-h4: 1.1em;
  --ba-font-size-h5: 1em;
  --ba-font-size-h6: 0.9em;
  --ba-font-size-p: 16px;
  --ba-font-size-li: 16px;
  --ba-font-size-a: 16px;
  --ba-font-size-span: inherit;
  --ba-font-size-code: 14px;
  --ba-font-size-small: 13px;

  /* Colors */
  --ba-text-color: inherit;
  --ba-heading-color: inherit;
  --ba-link-color: inherit;

  /* Decoration — set to 'underline' or 'none' */
  --ba-text-decoration: none;
  --ba-link-decoration: underline;

  /* Highlight — set a background color or 'transparent' */
  --ba-highlight-bg: transparent;
  --ba-highlight-color: inherit;
}

/* ===== Global font override ===== */
html, body, div, span, p, a, li, td, th, label,
input, textarea, select, button, blockquote, figcaption,
.text, .content, .article, .post, .entry, .description {
  font-family: var(--ba-font-family) !important;
  color: var(--ba-text-color) !important;
  text-decoration: var(--ba-text-decoration) !important;
}

/* ===== Body base size ===== */
body {
  font-size: var(--ba-font-size-body) !important;
}

/* ===== Heading sizes and color ===== */
h1 {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-h1) !important;
  color: var(--ba-heading-color) !important;
}

h2 {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-h2) !important;
  color: var(--ba-heading-color) !important;
}

h3 {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-h3) !important;
  color: var(--ba-heading-color) !important;
}

h4 {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-h4) !important;
  color: var(--ba-heading-color) !important;
}

h5 {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-h5) !important;
  color: var(--ba-heading-color) !important;
}

h6 {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-h6) !important;
  color: var(--ba-heading-color) !important;
}

/* ===== Element-specific sizes ===== */
p {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-p) !important;
}

li {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-li) !important;
}

a {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-a) !important;
  color: var(--ba-link-color) !important;
  text-decoration: var(--ba-link-decoration) !important;
}

span {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-span) !important;
}

code, pre, kbd, samp {
  font-size: var(--ba-font-size-code) !important;
}

small {
  font-family: var(--ba-font-family) !important;
  font-size: var(--ba-font-size-small) !important;
}

/* ===== Highlight effect ===== */
p, li, span, a, td, th, label, div {
  background-color: var(--ba-highlight-bg) !important;
}
